from itertools import combinations, product
INF=10**9

def uniform_matroid_rank(r, n):
    return lambda A: min(len(set(A)), r)

# define matroid by independent sets? let's build some small rank 2 with parallel elements e.g. partition classes
def partition_rank(classes, r=None):
    # rank = min(number of nonloop classes hit, r)
    cls_map={}
    for idx,cls in enumerate(classes):
        for e in cls:
            cls_map[e]=idx
    if r is None: r=len(classes)
    def rank(A):
        return min(len({cls_map[e] for e in A if cls_map[e] is not None}), r)
    return rank

def bases_from_rank(rank,n,r):
    return [tuple(c) for c in combinations(range(n),r) if rank(c)==r]

def trivial_val(rank,n,r):
    bases=set(bases_from_rank(rank,n,r))
    return {tuple(c):(0 if tuple(c) in bases else INF) for c in combinations(range(n),r)}

def gp_relations(val,n,r):
    # valuated Plucker: for S size r-2, T size r+2, min over pairs? Use tropical 3-term? For all S, distinct i,j,k,l: min p(Sij)+p(Skl),...
    if r<0: return False
    if r==0: return val.get((), INF)<INF
    if r==1:
        return any(v<INF for v in val.values())
    elems=range(n)
    for S in combinations(elems,r-2):
        rest=[e for e in elems if e not in S]
        for quad in combinations(rest,4):
            i,j,k,l=quad
            terms=[]
            for a,b,c,d in [(i,j,k,l),(i,k,j,l),(i,l,j,k)]:
                A=tuple(sorted(S+(a,b)))
                B=tuple(sorted(S+(c,d)))
                terms.append(val.get(A,INF)+val.get(B,INF))
            m=min(terms)
            if terms.count(m)<2 and m<INF:
                return False,("GP",S,quad,terms)
            if m>=INF:
                # all infinite or maybe one inf all; count(m)=3 if all INF
                if terms.count(m)<2: return False,("GPinf",S,quad,terms)
    return True,None

def incidence(theta,eta,n,a,b, nested_only=False):
    # theta rank a, eta rank b
    elems=range(n)
    if a==0:
        return True,None
    for I in combinations(elems,a-1):
        for J in combinations(elems,b+1):
            if nested_only and not set(I).issubset(J): continue
            terms=[]
            for i in set(J)-set(I):
                Ai=tuple(sorted(I+(i,)))
                Ji=tuple(sorted(set(J)-{i}))
                terms.append(theta.get(Ai,INF)+eta.get(Ji,INF))
            if not terms: 
                continue
            m=min(terms)
            if terms.count(m)<2:
                return False,("IP",I,J,terms)
    return True,None

def C_condition(theta,eta,n,d,rank_eta=None):
    elems=range(n)
    # D assumed separately
    if d<2: return True,None
    for S in combinations(elems,d-2):
        rest=[e for e in elems if e not in S]
        for x,y,z in combinations(rest,3):
            terms=[
                theta.get(tuple(sorted(S+(x,))),INF)+eta.get(tuple(sorted(S+(y,z))),INF),
                theta.get(tuple(sorted(S+(y,))),INF)+eta.get(tuple(sorted(S+(x,z))),INF),
                theta.get(tuple(sorted(S+(z,))),INF)+eta.get(tuple(sorted(S+(x,y))),INF),
            ]
            m=min(terms)
            if terms.count(m)<2:
                return False,("C",S,(x,y,z),terms)
    return True,None

def search_prop_counter(rank,n,d,vals=[0,1,INF], limit=1000000):
    eta=trivial_val(rank,n,d)
    keys=list(combinations(range(n),d-1))
    dep=[tuple(k) for k in keys if rank(k)<d-1]
    free=[k for k in keys if rank(k)==d-1]
    count=0
    for assign in product(vals, repeat=len(free)):
        theta={tuple(k):INF for k in keys}
        for k,v in zip(free,assign):
            theta[tuple(k)]=v
        if all(v>=INF for v in theta.values()): continue
        ok,why=C_condition(theta,eta,n,d)
        if not ok: continue
        okgp,whygp=gp_relations(theta,n,d-1)
        okip,whyip=incidence(theta,eta,n,d-1,d)
        if not (okgp and okip):
            return theta, eta, okgp, whygp, okip, whyip
        count+=1
        if count>limit: break
    return None, count

