def rank_from_bases(bases,n):
    bases=[set(b) for b in bases]
    def rank(A):
        A=set(A)
        return max((len(A & B) for B in bases), default=0)
    return rank

def support_rank(val,n,r):
    bases=[k for k,v in val.items() if v<INF]
    return rank_from_bases(bases,n)

def support_quotient(p,q,n,a,b):
    # p quotient of q iff rank_p(E)-rank_p(A) <= rank_q(E)-rank_q(A) for all A
    rp=support_rank(p,n,a); rq=support_rank(q,n,b)
    for mask in range(1<<n):
        A=[i for i in range(n) if mask>>i&1]
        if a-rp(A) > b-rq(A):
            return False
    return True

def all_valuated(n,r,vals=[0,1,INF], max_count=None):
    keys=list(combinations(range(n),r))
    c=0
    for assign in product(vals, repeat=len(keys)):
        val={k:v for k,v in zip(keys,assign)}
        if all(v>=INF for v in val.values()): continue
        ok,_=gp_relations(val,n,r)
        if ok:
            yield val
            c+=1
            if max_count and c>=max_count: return

